<script>(()=>{
const triggers=<?=json_encode($triggers,JSON_UNESCAPED_UNICODE|JSON_HEX_TAG)?>,templates=<?=json_encode($templates,JSON_UNESCAPED_UNICODE|JSON_HEX_TAG)?>,turmas=<?=json_encode($turmas,JSON_UNESCAPED_UNICODE|JSON_HEX_TAG)?>,tags=<?=json_encode($tags,JSON_UNESCAPED_UNICODE|JSON_HEX_TAG)?>,abStats=<?=json_encode($abStats,JSON_UNESCAPED_UNICODE|JSON_HEX_TAG)?>;
let graph=<?=json_encode($graph,JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES|JSON_HEX_TAG)?>;if(!Array.isArray(graph.nodes)||!Array.isArray(graph.edges))graph={schemaVersion:2,nodes:[],edges:[],viewport:{x:80,y:60,zoom:1}};graph.schemaVersion=2;graph.nodes.forEach(n=>{if(n.type==='tag')n.type='action';n.config=n.config||{};if(n.type==='trigger'&&!n.config.event)n.config.event='INSCRITO';if(n.type==='condition'&&!Array.isArray(n.config.rules))n.config.rules=[{field:n.config.field||'tag',operator:n.config.operator||'has',value:n.config.value||''}];});
const types={trigger:{label:'Gatilho inicial',color:'#38bdf8'},condition:{label:'Condição',color:'#10b981'},wait:{label:'Temporizador',color:'#fb7185'},email:{label:'Enviar e-mail',color:'#facc15'},ab_test:{label:'Teste A/B/n',color:'#a78bfa'},action:{label:'Ação de tag',color:'#f59e0b'},integration:{label:'Integração',color:'#a78bfa'},end:{label:'Encerrar',color:'#64748b'}};
const canvas=efCanvas,viewEl=efView,nodesEl=efNodes,edgesEl=efEdges,inspector=efInspector;let view=Object.assign({x:80,y:60,zoom:1},graph.viewport||{}),selected=null,pending=null,drag=null,pan=null;const uid=p=>p+'_'+Date.now().toString(36)+'_'+Math.random().toString(36).slice(2,7),esc=v=>String(v??'').replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]));
const options=(obj,val='')=>Object.entries(obj).map(([k,v])=>`<option value="${esc(k)}" ${String(k)===String(val)?'selected':''}>${esc(v)}</option>`).join('');
function defaults(t){return {condition:{label:'Nova condição',logic:'and',rules:[{field:'tag',operator:'has',value:''}]},wait:{label:'Aguardar',duration:1,unit:'hours',limitWindow:false,windowStart:'08:00',windowEnd:'20:00'},email:{label:'Enviar e-mail',templateVersionId:0,templateLabel:''},ab_test:{label:'Teste A/B/n',variants:[{id:uid('var'),label:'A',weight:50,templateVersionId:0,templateLabel:''},{id:uid('var'),label:'B',weight:50,templateVersionId:0,templateLabel:''}]},action:{label:'Alterar tag',action:'add_tag',tag:''},integration:{label:'Enviar integração',provider:'webhook',target:'',payload:''},end:{label:'Encerrar fluxo'}}[t]||{};}
function summary(n){const c=n.config||{};if(n.type==='trigger')return triggers[c.event]||'Selecione o evento';if(n.type==='condition')return `${(c.rules||[]).length} regra(s) · ${(c.logic||'and').toUpperCase()}`;if(n.type==='wait')return `${c.duration||1} ${{minutes:'minuto(s)',hours:'hora(s)',days:'dia(s)'}[c.unit]||''}`;if(n.type==='email')return c.templateLabel||'Selecione o modelo';if(n.type==='ab_test')return `${(c.variants||[]).length} variantes · peso total ${(c.variants||[]).reduce((s,v)=>s+(+v.weight||0),0)}%`;if(n.type==='action')return `${c.action==='remove_tag'?'Remover':'Adicionar'} ${c.tag||'tag'}`;return c.label||types[n.type].label;}
function apply(){view.zoom=Math.max(.35,Math.min(1.8,+view.zoom||1));viewEl.style.transform=`translate(${view.x}px,${view.y}px) scale(${view.zoom})`;efZoom.textContent=Math.round(view.zoom*100)+'%';graph.viewport={...view};}
function render(){nodesEl.innerHTML='';graph.nodes.forEach(n=>{const m=types[n.type];if(!m)return;const e=document.createElement('div');e.className='ef-node'+(selected===n.id?' selected':'');e.style.cssText=`left:${+n.x||0}px;top:${+n.y||0}px;--c:${m.color}`;e.innerHTML=`${n.type!=='trigger'?'<span class="ef-port in" data-port="in"></span>':''}<div class="ef-node-head"><span class="ef-dot"></span><strong>${esc(n.config?.label||m.label)}</strong></div><div class="ef-node-body">${esc(summary(n))}</div>${n.type==='condition'?'<span class="ef-port-label yes">SIM</span><span class="ef-port out yes" data-port="out" data-handle="yes"></span><span class="ef-port-label no">NÃO</span><span class="ef-port out no" data-port="out" data-handle="no"></span>':n.type!=='end'?'<span class="ef-port out" data-port="out" data-handle="default"></span>':''}`;e.onclick=x=>{if(x.target.closest('.ef-port'))return;selected=n.id;render();inspect()};e.querySelector('.ef-node-head').onpointerdown=x=>{x.stopPropagation();drag={n,sx:x.clientX,sy:x.clientY,ox:+n.x||0,oy:+n.y||0};canvas.setPointerCapture(x.pointerId)};e.querySelectorAll('.ef-port').forEach(p=>p.onclick=x=>port(x,n,p));nodesEl.appendChild(e)});requestAnimationFrame(edges);apply();}
function port(e,n,p){e.stopPropagation();if(p.dataset.port==='out'){pending={source:n.id,handle:p.dataset.handle||'default'};document.querySelectorAll('.ef-port.pending').forEach(x=>x.classList.remove('pending'));p.classList.add('pending');return}if(pending&&pending.source!==n.id){graph.edges=graph.edges.filter(x=>!(x.source===pending.source&&x.sourceHandle===pending.handle));graph.edges.push({id:uid('edge'),source:pending.source,target:n.id,sourceHandle:pending.handle});pending=null;render();}}
function edges(){edgesEl.innerHTML='';graph.edges.forEach(x=>{const s=graph.nodes.find(n=>n.id===x.source),t=graph.nodes.find(n=>n.id===x.target);if(!s||!t)return;const x1=(+s.x||0)+210,y1=(+s.y||0)+(s.type==='condition'?(x.sourceHandle==='yes'?58:84):80),x2=+t.x||0,y2=(+t.y||0)+40,b=Math.max(55,Math.abs(x2-x1)*.45),d=`M ${x1} ${y1} C ${x1+b} ${y1},${x2-b} ${y2},${x2} ${y2}`;const g=document.createElementNS('http://www.w3.org/2000/svg','g');g.setAttribute('class','ef-edge-g');g.innerHTML=`<path class="ef-edge" d="${d}"/><path class="ef-edge-hit" d="${d}"/>`;g.querySelector('.ef-edge-hit').onclick=()=>{if(confirm('Excluir esta conexão?')){graph.edges=graph.edges.filter(e=>e.id!==x.id);render()}};edgesEl.appendChild(g)});}
function add(t,x,y){if(t==='trigger'&&graph.nodes.some(n=>n.type==='trigger'))return alert('O fluxo aceita apenas um gatilho.');const n={id:uid(t),type:t,x,y,config:defaults(t)};graph.nodes.push(n);selected=n.id;render();inspect();}
function field(label,html){return `<div class="ef-field"><label>${label}</label>${html}</div>`}function bind(id,fn,event='input'){const e=document.getElementById(id);if(e)e.addEventListener(event,fn);}
const ruleFields={tag:'Possui tag',turma:'Está inscrito na turma',email:'Endereço de e-mail',email_delivered:'E-mail específico foi entregue',email_opened:'E-mail específico foi aberto',email_clicked:'E-mail específico recebeu clique',email_clicked_link:'Clicou em link específico do e-mail',email_bounced:'E-mail específico teve bounce',email_complaint:'E-mail específico teve reclamação',email_unsubscribed:'Descadastrou pelo e-mail específico',any_email_opened:'Abriu qualquer e-mail',any_email_clicked:'Clicou em qualquer e-mail',any_email_bounced:'Teve bounce em qualquer e-mail',engagement_count:'Quantidade de engajamentos',marketing_eligible:'Elegível para marketing'};
function ruleHtml(r,i){const field=String(r.field||''),needsTemplate=field.startsWith('email_'),needsValue=!['marketing_eligible'].includes(field);let value='';if(field==='tag'){const selected=Array.isArray(r.value)?r.value:(r.value?[r.value]:[]);value=`<select data-r="${i}" data-k="value" multiple size="7"><option value="" disabled>${tags.length?'Selecione uma ou mais tags':'Nenhuma tag cadastrada'}</option>${tags.map(x=>`<option value="${esc(x)}" ${selected.includes(x)?'selected':''}>${esc(x)}</option>`).join('')}</select><div class="ef-copy">Use Ctrl/Cmd ou Shift para selecionar mais de uma tag.</div>`;}else value=needsTemplate?`<select data-r="${i}" data-k="value"><option value="">Selecione o e-mail</option>${templates.map(t=>`<option value="${t.id}" ${String(r.value)===String(t.id)?'selected':''}>${esc(t.name)} · v${t.version_number}</option>`).join('')}</select>`:`<input data-r="${i}" data-k="value" value="${esc(r.value||'')}">`;if(r.field==='email_clicked_link')value+=`<input data-r="${i}" data-k="link" placeholder="URL exata ou parte da URL" value="${esc(r.link||'')}">`;return `<div class="ef-rule"><div class="ef-rule-head"><strong>Regra ${i+1}</strong><button type="button" class="ef-rule-remove" data-remove="${i}">Excluir</button></div><select data-r="${i}" data-k="field">${options(ruleFields,r.field)}</select><select data-r="${i}" data-k="operator">${options({has:'ocorreu / possui',not_has:'não ocorreu / não possui',equals:'é igual',not_equals:'é diferente',gte:'maior ou igual',lte:'menor ou igual'},r.operator)}</select>${needsValue?value:''}</div>`;}
function pct(a,b){return b>0?(100*a/b).toFixed(1).replace('.',',')+'%':'0,0%'}function templateOptions(value){return `<option value="">Selecione</option>${templates.map(t=>`<option value="${t.id}" ${String(value)===String(t.id)?'selected':''}>${esc(t.name)} · v${t.version_number} · ${esc(t.subject)}</option>`).join('')}`;}
function abVariantHtml(v,i){const s=abStats[String(v.templateVersionId)]||{},sent=+s.sent||0,delivered=+s.delivered||0,opened=+s.opened||0,clicked=+s.clicked||0,bounced=+s.bounced||0;return `<div class="ef-rule"><div class="ef-rule-head"><strong>Teste ${esc(v.label||String.fromCharCode(65+i))}</strong><button type="button" class="ef-rule-remove" data-ab-remove="${i}">Excluir</button></div><input data-ab="${i}" data-k="label" value="${esc(v.label||'')}"><input type="number" min="1" max="100" data-ab="${i}" data-k="weight" value="${esc(v.weight||0)}" placeholder="Peso %"><select data-ab="${i}" data-k="templateVersionId">${templateOptions(v.templateVersionId)}</select><div class="ef-copy">Envios: ${sent} · Entrega ${pct(delivered,sent)} · Abertura ${pct(opened,sent)} · Clique ${pct(clicked,sent)} · Bounce ${pct(bounced,sent)}</div></div>`;}
function inspect(){const n=graph.nodes.find(x=>x.id===selected);if(!n){inspector.innerHTML='<div class="ef-empty">Selecione um bloco no canvas.</div>';return}const c=n.config||(n.config={});let html=field('Rótulo',`<input id="iLabel" value="${esc(c.label||'')}">`);if(n.type==='trigger'){html+=field('Evento',`<select id="iEvent">${options(triggers,c.event)}</select>`)+field('Filtro de turma (opcional)',`<select id="iFilter"><option value="">Todas</option>${turmas.map(x=>`<option ${x===c.filter?'selected':''}>${esc(x)}</option>`).join('')}</select>`);if(c.event==='LIVE_LEMBRETE_AGENDADO')html+=field('Antecedência',`<input id="iAdvance" type="number" min="1" value="${c.advanceDuration||1}"><select id="iAdvanceUnit">${options({minutes:'minutos',hours:'horas',days:'dias'},c.advanceUnit)}</select>`);}if(n.type==='condition'){c.rules=Array.isArray(c.rules)&&c.rules.length?c.rules:[{field:'tag',operator:'has',value:''}];html+=field('Combinação',`<select id="iLogic">${options({and:'Todas as regras (E)',or:'Qualquer regra (OU)'},c.logic)}</select>`)+`<div id="rules">${c.rules.map(ruleHtml).join('')}</div><button type="button" class="btn btn-ghost btn-xs" id="addRule">+ Adicionar regra</button>`;}if(n.type==='wait')html+=field('Duração',`<input id="iDuration" type="number" min="1" value="${c.duration||1}">`)+field('Unidade',`<select id="iUnit">${options({minutes:'minutos',hours:'horas',days:'dias'},c.unit)}</select>`)+`<label class="ef-check"><input id="iWindow" type="checkbox" ${c.limitWindow?'checked':''}> Retomar somente em uma faixa de horário</label>`+field('Faixa',`<input id="iStart" type="time" value="${c.windowStart||'08:00'}"><input id="iEnd" type="time" value="${c.windowEnd||'20:00'}">`);if(n.type==='email')html+=field('Modelo publicado',`<select id="iTemplate">${templateOptions(c.templateVersionId)}</select>`)+`<div class="em-actions"><a class="btn btn-ghost btn-xs" target="_blank" href="email_editor.php">Criar novo e-mail</a><a class="btn btn-ghost btn-xs" target="_blank" href="email_modelos.php">Ver modelos</a></div>`;if(n.type==='ab_test'){c.variants=Array.isArray(c.variants)&&c.variants.length?c.variants:[{id:uid('var'),label:'A',weight:50,templateVersionId:0,templateLabel:''},{id:uid('var'),label:'B',weight:50,templateVersionId:0,templateLabel:''}];html+=`<div class="ef-field"><label>Variantes A/B/n</label><div class="ef-copy">O peso define a proporcao dos disparos. As taxas sao calculadas sobre os envios deste fluxo para cada modelo.</div>${c.variants.map(abVariantHtml).join('')}<button type="button" class="btn btn-ghost btn-xs" id="addVariant">+ Inserir teste</button></div>`;}if(n.type==='action')html+=field('Acao',`<select id="iTagAction">${options({add_tag:'Adicionar tag',remove_tag:'Remover tag'},c.action)}</select>`)+field('Tag',`<select id="iTag"><option value="">Selecione</option>${tags.map(x=>`<option ${x===c.tag?'selected':''}>${esc(x)}</option>`).join('')}</select>`);if(n.type==='integration')html+=field('Provedor',`<select id="iProvider">${options({webhook:'Webhook',superfuncionario:'SuperFuncionário',manychat:'ManyChat'},c.provider)}</select>`)+field('Destino / evento',`<input id="iTarget" value="${esc(c.target||'')}">`)+field('Payload JSON',`<textarea id="iPayload">${esc(c.payload||'')}</textarea>`);if(n.type!=='trigger')html+='<button type="button" class="btn btn-danger btn-sm" id="removeNode">Excluir bloco</button>';inspector.innerHTML='<div class="ef-fields">'+html+'</div>';
bind('iLabel',e=>{c.label=e.target.value;render()});bind('iEvent',e=>{c.event=e.target.value;render();inspect()},'change');bind('iFilter',e=>{c.filter=e.target.value;render()},'change');bind('iAdvance',e=>c.advanceDuration=+e.target.value);bind('iAdvanceUnit',e=>c.advanceUnit=e.target.value,'change');bind('iLogic',e=>{c.logic=e.target.value;render()},'change');bind('iDuration',e=>{c.duration=+e.target.value;render()});bind('iUnit',e=>{c.unit=e.target.value;render()},'change');bind('iWindow',e=>c.limitWindow=e.target.checked,'change');bind('iStart',e=>c.windowStart=e.target.value);bind('iEnd',e=>c.windowEnd=e.target.value);bind('iTemplate',e=>{c.templateVersionId=+e.target.value;c.templateLabel=e.target.options[e.target.selectedIndex].text;render()},'change');bind('iTagAction',e=>{c.action=e.target.value;render()},'change');bind('iTag',e=>{c.tag=e.target.value;render()},'change');bind('iProvider',e=>c.provider=e.target.value,'change');bind('iTarget',e=>c.target=e.target.value);bind('iPayload',e=>c.payload=e.target.value);
document.querySelectorAll('[data-ab]').forEach(e=>e.onchange=e.oninput=x=>{const i=+x.target.dataset.ab,k=x.target.dataset.k;if(!c.variants[i])return;c.variants[i][k]=k==='weight'?Math.max(1,+x.target.value||1):x.target.value;if(k==='templateVersionId'){c.variants[i].templateVersionId=+x.target.value;c.variants[i].templateLabel=x.target.options[x.target.selectedIndex].text;}render()});document.querySelectorAll('[data-ab-remove]').forEach(e=>e.onclick=()=>{if((c.variants||[]).length<=2)return alert('Mantenha pelo menos duas variantes.');c.variants.splice(+e.dataset.abRemove,1);inspect();render()});if(window.addVariant)addVariant.onclick=()=>{const label=String.fromCharCode(65+(c.variants||[]).length);c.variants.push({id:uid('var'),label,weight:1,templateVersionId:0,templateLabel:''});inspect();render()};document.querySelectorAll('[data-r]').forEach(e=>e.onchange=e.oninput=x=>{const i=+x.target.dataset.r,k=x.target.dataset.k;c.rules[i][k]=x.target.multiple?[...x.target.selectedOptions].map(o=>o.value).filter(Boolean):x.target.value;if(k==='field')inspect();render()});document.querySelectorAll('[data-remove]').forEach(e=>e.onclick=()=>{c.rules.splice(+e.dataset.remove,1);if(!c.rules.length)c.rules.push({field:'tag',operator:'has',value:''});inspect();render()});if(window.addRule)addRule.onclick=()=>{c.rules.push({field:'tag',operator:'has',value:''});inspect();render()};if(window.removeNode)removeNode.onclick=()=>{graph.nodes=graph.nodes.filter(x=>x.id!==n.id);graph.edges=graph.edges.filter(x=>x.source!==n.id&&x.target!==n.id);selected=null;render();inspect()};}
Object.entries(types).forEach(([t,m])=>{const b=document.createElement('button');b.type='button';b.className='ef-item';b.draggable=true;b.style.setProperty('--c',m.color);b.innerHTML='<span class="ef-dot"></span>'+esc(m.label);b.onclick=()=>add(t,220+graph.nodes.length*22,120+graph.nodes.length*18);b.ondragstart=e=>e.dataTransfer.setData('application/x-email-node',t);efPalette.appendChild(b)});canvas.ondragover=e=>e.preventDefault();canvas.ondrop=e=>{e.preventDefault();const t=e.dataTransfer.getData('application/x-email-node'),r=canvas.getBoundingClientRect();if(t)add(t,(e.clientX-r.left-view.x)/view.zoom,(e.clientY-r.top-view.y)/view.zoom)};canvas.onpointermove=e=>{if(drag){drag.n.x=Math.max(0,drag.ox+(e.clientX-drag.sx)/view.zoom);drag.n.y=Math.max(0,drag.oy+(e.clientY-drag.sy)/view.zoom);render()}else if(pan){view.x=pan.ox+e.clientX-pan.x;view.y=pan.oy+e.clientY-pan.y;apply()}};canvas.onpointerup=()=>{drag=pan=null};canvas.onpointerdown=e=>{if(e.target===canvas)pan={x:e.clientX,y:e.clientY,ox:view.x,oy:view.y}};canvas.onwheel=e=>{e.preventDefault();view.zoom*=e.deltaY<0?1.1:.9;apply()};efIn.onclick=()=>{view.zoom*=1.15;apply()};efOut.onclick=()=>{view.zoom*=.85;apply()};efZoom.onclick=()=>{view.zoom=1;apply()};efFit.onclick=()=>{view={x:60,y:50,zoom:1};apply()};document.querySelectorAll('[data-action]').forEach(b=>b.onclick=()=>efAction.value=b.dataset.action);efForm.onsubmit=()=>{graph.viewport={...view};efGraph.value=JSON.stringify(graph)};render();inspect();
})();</script><?php include __DIR__.'/_footer.php';
